import React from 'react';
import { Link } from 'react-router-dom';
import { useInView } from '../../hooks/useInView';
import './HomeFinalCta.css';

const HomeFinalCta = () => {
  const [ref, visible] = useInView();

  return (
    <section className="home-final-cta">
      <div className="container">
        <div
          ref={ref}
          className={`home-final-cta-inner reveal-group ${visible ? 'is-visible' : ''}`}
        >
          <h2 className="section-title reveal-item">How can we help?</h2>
          <p className="home-final-cta-text reveal-item">
            Tell us about your business and what you need. We will review your query and respond with
            clear next steps.
          </p>
          <div className="cta-center reveal-item">
            <Link to="/contact" className="btn-primary btn-large">
              Submit Your Query
            </Link>
          </div>
        </div>
      </div>
    </section>
  );
};

export default HomeFinalCta;
